package org.jsoup.parser;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
        features = "src/test/resources",
        glue = "org.jsoup.parser.steps"
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.select.Elements;

import static org.junit.Assert.*;

public class StepDefs {
    private String inputHtml;
    private Document parsedDocument;

    @Given("the input HTML {string}")
    public void the_input_HTML(String html) {
        this.inputHtml = html;
    }

    @When("the HTML is parsed")
    public void the_HTML_is_parsed() {
        try {
            this.parsedDocument = Jsoup.parse(inputHtml);
        } catch (Exception e) {
            // Store any exception for later verification if needed
            fail("Exception occurred during parsing: " + e.getMessage());
        }
    }

    @Then("the parsed document should contain an element {string}")
    public void the_parsed_document_should_contain_an_element(String tagName) {
        Elements elements = parsedDocument.getElementsByTag(tagName);
        assertTrue("Expected element " + tagName + " not found in document", !elements.isEmpty());
    }

    @Then("the element {string} should have an attribute {string} with value {string}")
    public void the_element_should_have_an_attribute_with_value(String tagName, String attributeName, String attributeValue) {
        Elements elements = parsedDocument.getElementsByTag(tagName);
        assertTrue("Element " + tagName + " not found", !elements.isEmpty());

        Element element = elements.first();
        assertTrue("Attribute " + attributeName + " not found on element " + tagName, element.hasAttr(attributeName));

        String actualValue = element.attr(attributeName);
        assertEquals("Attribute " + attributeName + " has incorrect value", attributeValue, actualValue);
    }
}

